				Expect(mf.ArtistID).NotTo(BeEmpty())
				Expect(mf.AlbumArtistID).NotTo(BeEmpty())
			}
		})
	})

	Describe("Incremental Scan", func() {
		It("detects no changes when files haven't been modified", func() {
