			changeCount, err := scanner.Scan(ctx, testLib, true, progress)
			close(progress)

			// Assert: Files should be discovered and imported
			Expect(err).NotTo(HaveOccurred())
			Expect(changeCount).To(Equal(int64(2)))

			// Verify files are in the database
			allFiles, err := ds.MediaFile(ctx).GetAll()
			Expect(err).NotTo(HaveOccurred())
			Expect(allFiles).To(HaveLen(2))

			// Verify file paths are correct
			filePaths := make(map[string]bool)
			for _, mf := range allFiles {
				filePaths[filepath.Base(mf.Path)] = true
			}
			Expect(filePaths).To(HaveKey("test.mp3"))
			Expect(filePaths).To(HaveKey("test.flac"))
		})

		It("extracts metadata from audio files", func() {
			// Setup: Copy test files with metadata
			copyTestAudioFile(testDir, "test.mp3")

			// Execute: Run scan
